function Hash([string]$Path){if([string]::IsNullOrWhiteSpace($Path)){throw 'NORA_CAPTURE_HASH_PATH_EMPTY'};if(!(Test-Path -LiteralPath $Path -PathType Leaf)){throw ('NORA_CAPTURE_HASH_PATH_NOT_FILE:'+[string]$Path)};(Get-FileHash -Algorithm SHA256 -LiteralPath $Path).Hash.ToLowerInvariant()}
function BytesHash([byte[]]$Bytes){([Security.Cryptography.SHA256]::Create().ComputeHash($Bytes)|ForEach-Object {$_.ToString('x2')}) -join ''}
function AtomicJson([string]$Path,$Value){$tmp=$Path+'.partial.'+[guid]::NewGuid().ToString('N');$Value|ConvertTo-Json -Depth 12 -Compress|Set-Content -LiteralPath $tmp -Encoding utf8 -NoNewline;if(Test-Path -LiteralPath $Path){$backup=$Path+'.replace-backup.'+[guid]::NewGuid().ToString('N');[IO.File]::Replace($tmp,$Path,$backup);Remove-Item -LiteralPath $backup -Force}else{[IO.File]::Move($tmp,$Path)}}
function NormalizePath([string]$Path){$Path.TrimStart('\').Replace('\','/')}
function NeedRunId(){if(!$RunId -or $RunId -notmatch '^[A-Za-z0-9][A-Za-z0-9._-]{2,127}$'){throw 'invalid run identity'}}
function Paths(){NeedRunId;return [ordered]@{incoming=(Join-Path $EvidenceRoot ('incoming\'+$RunId));running=(Join-Path $EvidenceRoot ('runs\'+$RunId+'.running'));complete=(Join-Path $EvidenceRoot ('runs\'+$RunId+'.complete'));returned=(Join-Path $EvidenceRoot ('returned\'+$RunId+'.published'));job=(Join-Path $EvidenceRoot ('jobs\'+$RunId+'.json'));stdout=(Join-Path $EvidenceRoot ('logs\'+$RunId+'.stdout.log'));stderr=(Join-Path $EvidenceRoot ('logs\'+$RunId+'.stderr.log'))}}
function Inventory([string]$Base){@(Get-ChildItem -LiteralPath $Base -File -Recurse -Force|Sort-Object FullName|ForEach-Object{[ordered]@{path=NormalizePath ($_.FullName.Substring($Base.Length));size=[int64]$_.Length;sha256=Hash $_.FullName}})}
function CurrentInventory([string]$Base){@(Get-ChildItem -LiteralPath $Base -Force -Recurse|Sort-Object FullName|ForEach-Object{[ordered]@{path=NormalizePath ($_.FullName.Substring($Base.Length));type=if($_.PSIsContainer){'directory'}else{'file'};reparse=(($_.Attributes -band [IO.FileAttributes]::ReparsePoint) -ne 0);size=if($_.PSIsContainer){$null}else{[int64]$_.Length};sha256=if($_.PSIsContainer){$null}else{Hash $_.FullName}}})}
function Identity(){ $i=[Security.Principal.WindowsIdentity]::GetCurrent();[ordered]@{name=$i.Name;sid=$i.User.Value} }
function AtomicText([string]$Path,[string]$Value){$tmp=$Path+'.partial.'+[guid]::NewGuid().ToString('N');[IO.File]::WriteAllText($tmp,$Value,[Text.UTF8Encoding]::new($false));if(Test-Path -LiteralPath $Path){throw 'immutable evidence path already exists'};[IO.File]::Move($tmp,$Path)}
