function FirewallComparable($Value){
 $clone=($Value|ConvertTo-Json -Depth 30 -Compress)|ConvertFrom-Json
 $clone.captured_utc=$null;$clone.diagnostics=$null
 foreach($section in @('effective_rules','persistent_rules')){foreach($r in @($clone.$section)){$r.display_name=$null;$r.description=$null;$r.diagnostics=$null}}
 ($clone|ConvertTo-Json -Depth 30 -Compress)
}
function FirewallVerdict($Pre,$Post){
 $violations=@();foreach($p in @($Pre.value.profiles)+@($Post.value.profiles)){if(!$p.enabled){$violations+='profile_disabled:'+[string]$p.name}}
 foreach($v in @($Pre.value,$Post.value)){foreach($r in @($v.effective_rules)){if(([string]$r.name).ToLowerInvariant().StartsWith('noraphase2containment-')-or([string]$r.group).ToLowerInvariant().StartsWith('noraphase2containment-')){$violations+='stale_nora_rules'};if($r.enabled-and([string]$r.action).ToLowerInvariant() -eq 'allow'){foreach($p in @($r.programs)){if(([string]$p).ToLowerInvariant().EndsWith('\terminal64.exe')-or([string]$p).ToLowerInvariant().EndsWith('\metatester64.exe')){$violations+='unsafe_executable_allow'}}}}}
 $preText=FirewallComparable $Pre.value;$postText=FirewallComparable $Post.value
 [ordered]@{schema_version='nora.phase2_operation_firewall_binding_v2';capture_tool_path=$FirewallCaptureToolPath;capture_tool_sha256=$FirewallCaptureToolSha256;pre_inventory=[ordered]@{path=(Split-Path -Leaf $Pre.path);size=$Pre.size;sha256=$Pre.sha256};post_inventory=[ordered]@{path=(Split-Path -Leaf $Post.path);size=$Post.size;sha256=$Post.sha256};pre_capture_digest=BytesHash ([Text.Encoding]::UTF8.GetBytes($preText));post_capture_digest=BytesHash ([Text.Encoding]::UTF8.GetBytes($postText));windows_semantic_equal=($preText -eq $postText);windows_invariant_verdict=if($violations.Count){'FAIL'}else{'PASS'};violations=@($violations);capture_order=@('pre','operation','post')}
}
function AclView([string]$Path){$a=Get-Acl -LiteralPath $Path;[ordered]@{owner=$a.Owner;sddl=$a.Sddl;protected=$a.AreAccessRulesProtected;access=@($a.Access|ForEach-Object{[ordered]@{identity=$_.IdentityReference.Value;rights=[string]$_.FileSystemRights;type=[string]$_.AccessControlType;inherited=$_.IsInherited}})}}
function RuleSid($Rule){try{return $Rule.IdentityReference.Translate([Security.Principal.SecurityIdentifier]).Value}catch{throw 'unresolvable ACL principal'}}
function AssertSecureAcl([string]$Path,[bool]$RequireProtected=$false){$a=Get-Acl -LiteralPath $Path;if($RequireProtected -and !$a.AreAccessRulesProtected){throw 'evidence root ACL inheritance enabled'};$broad='S-1-1-0','S-1-5-11','S-1-5-32-545';foreach($rule in @($a.Access)){if(($broad -contains (RuleSid $rule)) -and ([string]$rule.FileSystemRights -match 'Write|Modify|FullControl|Delete')){throw 'broad evidence write ACL'}}}
function SecureAcl([string]$Path,[bool]$Container,[string]$RunnerSid){$acl=if($Container){New-Object Security.AccessControl.DirectorySecurity}else{New-Object Security.AccessControl.FileSecurity};$acl.SetAccessRuleProtection($true,$false);foreach($sidText in @('S-1-5-18','S-1-5-32-544',$RunnerSid)){ $sid=New-Object Security.Principal.SecurityIdentifier($sidText);$inherit=if($Container){[Security.AccessControl.InheritanceFlags]'ContainerInherit, ObjectInherit'}else{[Security.AccessControl.InheritanceFlags]::None};$rule=New-Object Security.AccessControl.FileSystemAccessRule($sid,[Security.AccessControl.FileSystemRights]::FullControl,$inherit,[Security.AccessControl.PropagationFlags]::None,[Security.AccessControl.AccessControlType]::Allow);$acl.AddAccessRule($rule)};$acl.SetOwner((New-Object Security.Principal.SecurityIdentifier($RunnerSid)));Set-Acl -LiteralPath $Path -AclObject $acl}
function WriteJob($paths,[string]$State,$extra=@{}){ $old=if(Test-Path -LiteralPath $paths.job){Get-Content -LiteralPath $paths.job -Raw|ConvertFrom-Json}else{$null};$value=[ordered]@{};if($old){foreach($p in $old.PSObject.Properties){$value[$p.Name]=$p.Value}};$value.schema_version=$schema;$value.run_identifier=$RunId;$value.state=$State;$value.updated_utc=(Get-Date).ToUniversalTime().ToString('o');$value.evidence_root=$EvidenceRoot;$value.runner_identity=Identity;$value.runner_script_path=$PSCommandPath;$value.runner_script_sha256=Hash $PSCommandPath;$value.terminal_path=$terminal;$value.paths=$paths;if(!$value.created_utc){$value.created_utc=$value.updated_utc};foreach($key in $extra.Keys){$value[$key]=$extra[$key]};AtomicJson $paths.job $value;return $value }
function RequireSecureRoot(){
 if(!(Test-Path -LiteralPath $EvidenceRoot -PathType Container)){throw 'missing evidence root'}
 $volume=Get-Volume -DriveLetter ([IO.Path]::GetPathRoot($EvidenceRoot).TrimEnd(':','\'))
 if($volume.HealthStatus -ne 'Healthy'){throw 'unhealthy evidence volume'}
 if($volume.SizeRemaining -lt 5GB){throw 'insufficient evidence free space'}
 AssertSecureAcl $EvidenceRoot $true;$tree=@($EvidenceRoot)+@(Get-ChildItem -LiteralPath $EvidenceRoot -Recurse -Force|ForEach-Object{$_.FullName});foreach($path in @($tree|Select-Object -Skip 1)){AssertSecureAcl $path}
 return [ordered]@{volume_health=[string]$volume.HealthStatus;free_bytes=[int64]$volume.SizeRemaining;acl=(AclView $EvidenceRoot);secured_path_count=$tree.Count;identity=Identity}
