 [ordered]@{pid=[int]$process.ProcessId;parent_pid=[int]$process.ParentProcessId;start_time_utc=if($process.CreationDate){([datetime]$process.CreationDate).ToUniversalTime().ToString('o')}else{$null};executable_path=[string]$process.ExecutablePath;command_line=[string]$process.CommandLine;session_id=[int]$process.SessionId}
