 $directory=FailureDirectory $paths;$stdoutHash=if(Test-Path -LiteralPath $paths.stdout){Hash $paths.stdout}else{$null};$stderrHash=if(Test-Path -LiteralPath $paths.stderr){Hash $paths.stderr}else{$null};$job=if(Test-Path -LiteralPath $paths.job){Get-Content -LiteralPath $paths.job -Raw|ConvertFrom-Json}else{$null}
 $value=[ordered]@{schema_version='nora.phase2_detached_lifecycle_failure_v1';run_identifier=$RunId;exception_type=$ExceptionType;message=$Message;position_or_stack=if($Position){$Position.Substring(0,[Math]::Min(4096,$Position.Length))}else{$null};exit_code=$ExitCode;last_completed_lifecycle_step=$LastStep;stdout_path=$paths.stdout;stdout_sha256=$stdoutHash;stderr_path=$paths.stderr;stderr_sha256=$stderrHash;worker_pid=if($job.workload_binding){$job.workload_binding.pid}elseif($job.bootstrap_binding){$job.bootstrap_binding.pid}else{$null};worker_start_time_utc=if($job.workload_binding){$job.workload_binding.start_time_utc}elseif($job.bootstrap_binding){$job.bootstrap_binding.start_time_utc}else{$null};worker_script_path=if($job.workload_script_path){$job.workload_script_path}else{$WorkloadPath};worker_script_sha256=if($job.workload_sha256){$job.workload_sha256}else{$WorkloadSha256};configuration_path=if($job.configuration_path){$job.configuration_path}else{$ConfigurationPath};configuration_sha256=if($job.configuration_sha256){$job.configuration_sha256}else{$ConfigurationSha256};failure_utc=(Get-Date).ToUniversalTime().ToString('o')}
 AtomicJson (Join-Path $directory 'lifecycle-failure.json') $value;return $value
}
