 try{$created=Invoke-CimMethod -ClassName Win32_Process -MethodName Create -Arguments @{CommandLine=$command} -ErrorAction Stop}catch{$failure=WriteLifecycleFailure $paths $_.Exception.GetType().FullName $_.Exception.Message 70 'launch-requested' $_.ScriptStackTrace;WriteJob $paths 'failed' @{failure_record_sha256=Hash (Join-Path (FailureDirectory $paths) 'lifecycle-failure.json')}|Out-Null;throw}
 if($created.ReturnValue-ne0){$failure=WriteLifecycleFailure $paths 'Win32ProcessCreateFailure' ('Win32_Process.Create returned '+$created.ReturnValue) ([int]$created.ReturnValue) 'launch-requested';WriteJob $paths 'failed' @{failure_record_sha256=Hash (Join-Path (FailureDirectory $paths) 'lifecycle-failure.json')}|Out-Null;throw 'detached process creation failed'}
